const staticData = $getWorkflowStaticData('global');
const sinceToken = staticData.sinceToken || '';
const homeserver = $env.MATRIX_HOMESERVER;
const botToken = $env.MATRIX_BOT_TOKEN;
const todoRoom = $env.MATRIX_ROOM_TODO;
const qaRoom = $env.MATRIX_ROOM_QA || '';

if (!homeserver || !botToken) {
  return [];
}

// 监听的房间列表
const rooms = [todoRoom];
if (qaRoom) rooms.push(qaRoom);

const filter = JSON.stringify({
  room: {
    rooms: rooms,
    timeline: { types: ['m.room.message'], limit: 20 }
  },
  presence: { types: [] },
  account_data: { types: [] }
});

// timeout=8000: long-polling, returns immediately when new events arrive
let syncUrl = `${homeserver}/_matrix/client/v3/sync?timeout=8000&filter=${encodeURIComponent(filter)}`;
if (sinceToken) {
  syncUrl += `&since=${encodeURIComponent(sinceToken)}`;
}

return [{ json: { syncUrl, isFirstRun: !sinceToken, todoRoom, qaRoom } }];

const staticData = $getWorkflowStaticData('global');
const syncResp = $input.first().json;
const prevData = $('准备同步').first().json;
const isFirstRun = prevData.isFirstRun;
const todoRoom = prevData.todoRoom;
const qaRoom = prevData.qaRoom;

// 保存 next_batch token
if (syncResp.next_batch) {
  staticData.sinceToken = syncResp.next_batch;
}

// 首次运行或出错时跳过
if (isFirstRun || syncResp.errcode) {
  return [];
}

// 房间到 bot_type 的映射
const roomMap = {};
if (todoRoom) roomMap[todoRoom] = 'todo';
if (qaRoom) roomMap[qaRoom] = 'qa';

const results = [];
const joinedRooms = syncResp.rooms?.join || {};

for (const [roomId, roomData] of Object.entries(joinedRooms)) {
  const botType = roomMap[roomId];
  if (!botType) continue;

  const events = roomData.timeline?.events || [];

  for (const event of events) {
    if (event.type !== 'm.room.message') continue;
    // 过滤 bot 自己的消息
    if (event.sender && event.sender.startsWith('@kb-bot:')) continue;

    const body = (event.content?.body || '').trim();
    // 只处理以 ! 或 ！ 开头的指令
    if (!body.startsWith('!') && !body.startsWith('！')) continue;

    results.push({
      bot_type: botType,
      room_id: roomId,
      sender: event.sender,
      raw_message: body,
      event_id: event.event_id
    });
  }
}

return results.length > 0 ? results.map(r => ({ json: r })) : [];

const input = $input.first().json;
const botType = input.bot_type;
const rawMessage = input.raw_message;

// 移除开头的 ! 或 ！
const content = rawMessage.substring(1).trim();
const parts = content.split(/\s+/);
const cmd = parts[0];
const args = parts.slice(1).join(' ');

let command = '';
let parsedArgs = {};

// 根据 bot_type 解析指令
if (botType === 'todo') {
  // 待办机器人指令
  switch(cmd) {
    case '待办': case '列表': case '待办列表':
    case '查询': case '查看':
      command = 'list';
      break;
    case '今日': case '今天':
      command = 'list';
      parsedArgs.filter = 'today';
      break;
    case '逾期':
      command = 'list';
      parsedArgs.filter = 'overdue';
      break;
    case '新增': case '添加':
      if (args) {
        command = 'add';
        let priority = 3;
        let dueDate = '';
        let remaining = args;
        // 解析 P1, D3/15 等参数
        for (let i = 0; i < 2; i++) {
          const pMatch = remaining.match(/^P(\d)\s+([\s\S]*)/);
          if (pMatch) { priority = parseInt(pMatch[1]); remaining = pMatch[2]; continue; }
          const dFull = remaining.match(/^D(\d{4}-\d{1,2}-\d{1,2})\s+([\s\S]*)/);
          if (dFull) { dueDate = dFull[1]; remaining = dFull[2]; continue; }
          const dShort = remaining.match(/^D(\d{1,2})\/(\d{1,2})\s+([\s\S]*)/);
          if (dShort) {
            const y = new Date().getFullYear();
            dueDate = `${y}-${dShort[1].padStart(2,'0')}-${dShort[2].padStart(2,'0')}`;
            remaining = dShort[3]; continue;
          }
          break;
        }
        parsedArgs.text = remaining.trim();
        parsedArgs.priority = priority;
        parsedArgs.dueDate = dueDate;
      }
      break;
    case '完成':
      if (args) {
        command = 'done';
        parsedArgs.memo_name = `memos/${args}`;
      }
      break;
    case '删除':
      if (args) {
        command = 'delete';
        parsedArgs.memo_name = `memos/${args}`;
      }
      break;
    case '修改': {
      const modParts = args.split(/\s+/);
      if (modParts.length >= 2) {
        command = 'modify';
        parsedArgs.memo_name = `memos/${modParts[0]}`;
        parsedArgs.text = modParts.slice(1).join(' ');
      }
      break;
    }
    case '帮助': case 'help':
      command = 'help';
      break;
  }
} else if (botType === 'qa') {
  // 问答机器人指令
  switch(cmd) {
    case '问': case 'ask':
      if (args) {
        command = 'ask';
        parsedArgs.question = args;
      }
      break;
    case '搜': case '搜索': case 'search':
      if (args) {
        command = 'search';
        parsedArgs.keywords = args;
      }
      break;
    case '帮助': case 'help':
      command = 'help';
      break;
  }
}

// 如果没有识别到有效指令，设置为 unknown
if (!command) {
  command = 'unknown';
}

return [{
  json: {
    bot_type: botType,
    room_id: input.room_id,
    sender: input.sender,
    command: command,
    args: parsedArgs,
    raw_message: rawMessage
  }
}];

const input = $('解析指令').first().json;
const botType = input.bot_type;

let message = '';
let html = '';

if (botType === 'todo') {
  message = '📖 待办指令帮助

📋 查看
  !列表 - 查看所有待办
  !今日 - 查看今日到期
  !逾期 - 查看已逾期

📝 管理
  !新增 {内容} - 添加待办
  !新增 P1 {内容} - 指定优先级(P1最高)
  !新增 D3/15 {内容} - 指定截止日期
  !新增 P1 D3/15 {内容} - 同时指定
  !完成 {ID} - 标记完成
  !删除 {ID} - 删除待办
  !修改 {ID} {新内容} - 修改内容

示例: !新增 P1 D3/15 完成周报';
