} else if (botType === 'qa') {
  message = '🤖 知识库助手帮助

基础:
  !问 {问题} - 向知识库提问
  !搜 {关键词} - 搜索相关文档
  !帮助 - 显示此帮助

示例:
  !问 如何配置 RAGFlow
  !搜 Docker 部署';
  html = '<h4>🤖 知识库助手帮助</h4><h5>基础</h5><ul><li><code>!问 {问题}</code> - 向知识库提问</li><li><code>!搜 {关键词}</code> - 搜索相关文档</li><li><code>!帮助</code> - 显示此帮助</li></ul><p><i>示例: !问 如何配置 RAGFlow</i></p>';
} else {
  message = '❓ 未知机器人类型';
  html = '<p>❓ 未知机器人类型</p>';
}

return [{ json: { message, html, bot_type: botType } }];

const input = $('解析指令').first().json;
const message = '❓ 未知指令，发送 !帮助 查看用法';
const html = '<p>❓ 未知指令，发送 <code>!帮助</code> 查看用法</p>';
return [{ json: { message, html, bot_type: input.bot_type } }];

const command = $('解析指令').first().json;
const response = $input.first().json;
const action = command.command;
const filter = command.args.filter || '';
const botType = command.bot_type;

let message = '';
let html = '';

if (response.success === false || response.error) {
  message = `❌ 操作失败: ${response.error || '未知错误'}`;
  html = `<p>❌ 操作失败: ${response.error || '未知错误'}</p>`;
} else {
  switch(action) {
    case 'list': {
      let memos = response.memos || [];
      const now = new Date();
      const todayStr = `${now.getFullYear()}-${String(now.getMonth()+1).padStart(2,'0')}-${String(now.getDate()).padStart(2,'0')}`;

      if (filter === 'today') {
        memos = memos.filter(m => {
          const d = (m.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          return d && d[1] === todayStr;
        });
      } else if (filter === 'overdue') {
        memos = memos.filter(m => {
          const d = (m.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          return d && d[1] < todayStr;
        });
      }

      const filterLabel = filter === 'today' ? '今日到期' : filter === 'overdue' ? '逾期' : '待办列表';

      if (memos.length === 0) {
        const emptyMsg = filter === 'today' ? '今日没有到期事项' : filter === 'overdue' ? '没有逾期事项' : '当前没有待办事项';
        message = `📝 ${emptyMsg}`;
        html = `<p>📝 <i>${emptyMsg}</i></p>`;
      } else {
        memos.sort((a, b) => {
          const dA = (a.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          const dB = (b.content || '').match(/#D:(\d{4}-\d{2}-\d{2})/);
          const dateA = dA ? dA[1] : '9999-99-99';
          const dateB = dB ? dB[1] : '9999-99-99';
          const overA = dA && dA[1] < todayStr ? 0 : 1;
          const overB = dB && dB[1] < todayStr ? 0 : 1;
          if (overA !== overB) return overA - overB;
          if (dateA !== dateB) return dateA.localeCompare(dateB);
          const pA = parseInt((a.content?.match(/#P(\d)/) || [])[1] || '3');
          const pB = parseInt((b.content?.match(/#P(\d)/) || [])[1] || '3');
          return pA - pB;
        });

        const lines = [`📝 ${filterLabel} (${memos.length}项):`];
        html = `<h4>📝 ${filterLabel} (${memos.length}项)</h4>\n<ul>\n`;
        memos.forEach((memo, i) => {
          const content = memo.content || '';
          const text = content.replace(/#\S+/g, '').trim();
          const id = (memo.name || '').replace('memos/', '');
          const priority = (content.match(/#P(\d)/) || [])[1] || '3';
          const pEmoji = priority === '1' ? '🔴' : priority === '2' ? '🟡' : '⚪';
          const dueMatch = content.match(/#D:(\d{4})-(\d{2})-(\d{2})/);
          let dateStr = '';
          let htmlDate = '';
          if (dueMatch) {
            const isOverdue = `${dueMatch[1]}-${dueMatch[2]}-${dueMatch[3]}` < todayStr;
            const isToday = `${dueMatch[1]}-${dueMatch[2]}-${dueMatch[3]}` === todayStr;
            dateStr = isOverdue ? ` ⚠️${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}(逾期)` : isToday ? ` 📅今日` : ` 📅${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}`;
            htmlDate = isOverdue ? ` <b>⚠️${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}</b>` : isToday ? ` 📅今日` : ` 📅${parseInt(dueMatch[2])}/${parseInt(dueMatch[3])}`;
          }
          lines.push(`${pEmoji} ${i+1}. [#${id}] P${priority}${dateStr} ${text}`);
          html += `<li>${pEmoji} <code>#${id}</code> P${priority}${htmlDate} ${text}</li>\n`;
        });
        message = lines.join('\n');
        html += `</ul>`;
      }
      break;
    }
    case 'add': {
      let extra = '';
      if (command.args.dueDate) {
        const dp = command.args.dueDate.split('-');
        extra = ` (📅${parseInt(dp[1])}/${parseInt(dp[2])})`;
      }
      message = `➕ 已添加待办: ${command.args.text}${extra}`;
      html = `<p>➕ 已添加待办: <b>${command.args.text}</b>${extra}</p>`;
      break;
    }
    case 'done':
      message = `✅ 已完成: ${(command.args.memo_name || '').replace('memos/', '#')}`;
      html = `<p>✅ 已完成: <code>${(command.args.memo_name || '').replace('memos/', '#')}</code></p>`;
      break;
    case 'delete':
      message = `🗑️ 已删除: ${(command.args.memo_name || '').replace('memos/', '#')}`;
      html = `<p>🗑️ 已删除: <code>${(command.args.memo_name || '').replace('memos/', '#')}</code></p>`;
      break;
    case 'modify':
      message = `✏️ 已修改: ${command.args.text}`;
      html = `<p>✏️ 已修改: <b>${command.args.text}</b></p>`;
      break;
    default:
      message = `❓ 未知操作: ${action}`;
      html = `<p>❓ 未知操作: ${action}</p>`;
  }
}

return [{ json: { message, html, bot_type: botType } }];

const command = $('解析指令').first().json;
const response = $input.first().json;
const botType = command.bot_type;

let message = '';
let html = '';

if (response.success === false || response.error) {
  message = `❌ 操作失败: ${response.error || '未知错误'}`;
  html = `<p>❌ 操作失败: ${response.error || '未知错误'}</p>`;
} else if (response.message) {
  message = response.message;
  html = `<p>${response.message}</p>`;
} else {
  message = '✅ 操作成功';
  html = `<p>✅ 操作成功</p>`;
}

return [{ json: { message, html, bot_type: botType } }];

const input = $input.first().json;
const botType = input.bot_type;
const message = input.message;
const html = input.html || null;

const roomMap = {
  'todo': 'todo',
  'qa': 'qa'
};

const room = roomMap[botType] || 'todo';

return [{ json: { room, message, html } }];
